// lib/data.ts

import { sql } from '@vercel/postgres';
// If you're using different database, import appropriate client

/**
 * Fetches all available genres from the database
 * @returns Promise<string[]> Array of genre names
 * @throws Error if database query fails
 */
export async function fetchGenres(): Promise<string[]> {
  try {
    // Example using Vercel Postgres
    const result = await sql`
      SELECT DISTINCT genre 
      FROM movies 
      WHERE genre IS NOT NULL 
      ORDER BY genre ASC;
    `;

    if (!result || !result.rows) {
      throw new Error("No data returned from database");
    }

    // Extract genres from the result
    const genres = result.rows.map(row => row.genre as string)
      .filter(Boolean) // Remove any null/undefined values
      .filter((value, index, self) => self.indexOf(value) === index); // Remove duplicates

    if (genres.length === 0) {
      console.warn("No genres found in database");
      return []; // Return empty array instead of throwing error
    }

    return genres;

  } catch (error) {
    console.error("Error fetching genres from database:", error);
    
    // Include more detailed error information in development
    if (process.env.NODE_ENV === 'development') {
      throw new Error(`Failed to fetch genres: ${error instanceof Error ? error.message : 'Unknown error'}`);
    }
    
    // Generic error in production
    throw new Error("Failed to fetch genres. Please try again later.");
  }
}

/**
 * Alternative implementation using hardcoded genres as fallback
 * Useful during development or if database is not yet set up
 */
export async function fetchGenresWithFallback(): Promise<string[]> {
  try {
    return await fetchGenres();
  } catch (error) {
    console.warn("Falling back to default genres due to error:", error);
    
    // Fallback genres
    return [
      "Action",
      "Adventure",
      "Comedy",
      "Drama",
      "Horror",
      "Romance",
      "Sci-Fi",
      "Thriller"
    ];
  }
}

